def merge_ranges(pairs):
    sorted_pairs = sorted(pairs, key=lambda x: x[0])
    merged_ranges = [sorted_pairs[0]]

    for pair in sorted_pairs[1:]:
        last_range = merged_ranges[-1]
        if last_range[1] >= pair[0]:
            last_range[1] = max(last_range[1], pair[1])
        else:
            merged_ranges.append(pair)

    return merged_ranges
